use sqlx::PgPool;

use crate::domain::{
    ContextId, InboxItem, InboxItemId, NextAction, Project, TodoTitle, TodoTitleError, UserId,
    WaitingForItem, WaitingOn, WaitingOnError,
};
use crate::infrastructure::inbox_repository;
use crate::infrastructure::next_action_repository;
use crate::infrastructure::project_repository;
use crate::infrastructure::waiting_for_repository;

#[derive(Debug, thiserror::Error)]
pub enum CaptureInboxError {
    #[error("Invalid title: {0}")]
    InvalidTitle(#[from] TodoTitleError),
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "capture_inbox_item",
    skip(pool, title),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn capture_inbox_item(
    pool: &PgPool,
    user_id: UserId,
    title: String,
) -> Result<InboxItem, CaptureInboxError> {
    let title = TodoTitle::parse(title)?;
    let item = InboxItem::new(user_id, title);

    inbox_repository::insert_inbox_item(pool, &item)
        .await
        .map_err(|e| {
            CaptureInboxError::Unexpected(anyhow::anyhow!("Failed to insert inbox item: {e}"))
        })?;

    tracing::info!("Inbox item captured");
    Ok(item)
}

#[tracing::instrument(
    name = "get_inbox_items",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn get_inbox_items(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<InboxItem>, anyhow::Error> {
    let items = inbox_repository::find_inbox_items_by_user(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to fetch inbox items: {e}"))?;

    Ok(items)
}

#[tracing::instrument(
    name = "get_inbox_count",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn get_inbox_count(pool: &PgPool, user_id: &UserId) -> Result<i64, anyhow::Error> {
    let count = inbox_repository::count_inbox_items(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to count inbox items: {e}"))?;

    Ok(count)
}

#[derive(Debug, thiserror::Error)]
pub enum DeleteInboxError {
    #[error("Inbox item not found")]
    NotFound,
    #[error("Not authorized to delete this inbox item")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "delete_inbox_item",
    skip(pool),
    fields(item_id = %item_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn delete_inbox_item(
    pool: &PgPool,
    item_id: &InboxItemId,
    user_id: &UserId,
) -> Result<(), DeleteInboxError> {
    let item = inbox_repository::find_inbox_item_by_id(pool, item_id)
        .await
        .map_err(|e| DeleteInboxError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(DeleteInboxError::NotFound)?;

    if item.user_id() != user_id {
        return Err(DeleteInboxError::Unauthorized);
    }

    inbox_repository::delete_inbox_item(pool, item_id)
        .await
        .map_err(|e| {
            DeleteInboxError::Unexpected(anyhow::anyhow!("Failed to delete inbox item: {e}"))
        })?;

    tracing::info!("Inbox item deleted");
    Ok(())
}

#[derive(Debug, thiserror::Error)]
pub enum ClarifyAsNextActionError {
    #[error("Inbox item not found")]
    NotFound,
    #[error("Not authorized to clarify this inbox item")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "clarify_as_next_action",
    skip(pool),
    fields(item_id = %item_id.as_uuid(), user_id = %user_id.as_uuid(), context_id = %context_id.as_uuid())
)]
pub async fn clarify_as_next_action(
    pool: &PgPool,
    item_id: &InboxItemId,
    user_id: &UserId,
    context_id: ContextId,
) -> Result<NextAction, ClarifyAsNextActionError> {
    let mut tx = pool.begin().await.map_err(|e| {
        ClarifyAsNextActionError::Unexpected(anyhow::anyhow!("Failed to begin transaction: {e}"))
    })?;

    let item = inbox_repository::find_inbox_item_by_id(&mut *tx, item_id)
        .await
        .map_err(|e| ClarifyAsNextActionError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(ClarifyAsNextActionError::NotFound)?;

    if item.user_id() != user_id {
        return Err(ClarifyAsNextActionError::Unauthorized);
    }

    let action = NextAction::new(user_id.clone(), context_id, item.title().clone());

    next_action_repository::insert_next_action(&mut *tx, &action)
        .await
        .map_err(|e| {
            ClarifyAsNextActionError::Unexpected(anyhow::anyhow!(
                "Failed to insert next action: {e}"
            ))
        })?;

    inbox_repository::delete_inbox_item(&mut *tx, item_id)
        .await
        .map_err(|e| {
            ClarifyAsNextActionError::Unexpected(anyhow::anyhow!(
                "Failed to delete inbox item: {e}"
            ))
        })?;

    tx.commit().await.map_err(|e| {
        ClarifyAsNextActionError::Unexpected(anyhow::anyhow!("Failed to commit transaction: {e}"))
    })?;

    tracing::info!("Inbox item clarified as next action");
    Ok(action)
}

#[derive(Debug, thiserror::Error)]
pub enum ClarifyAsProjectError {
    #[error("Inbox item not found")]
    NotFound,
    #[error("Not authorized to clarify this inbox item")]
    Unauthorized,
    #[error("Invalid first action title: {0}")]
    InvalidTitle(#[from] TodoTitleError),
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

pub struct ClarifyAsProjectResult {
    pub project: Project,
    pub first_action: NextAction,
}

#[tracing::instrument(
    name = "clarify_as_project",
    skip(pool, first_action_title),
    fields(item_id = %item_id.as_uuid(), user_id = %user_id.as_uuid(), context_id = %context_id.as_uuid())
)]
pub async fn clarify_as_project(
    pool: &PgPool,
    item_id: &InboxItemId,
    user_id: &UserId,
    context_id: ContextId,
    first_action_title: String,
) -> Result<ClarifyAsProjectResult, ClarifyAsProjectError> {
    let first_action_title = TodoTitle::parse(first_action_title)?;

    let mut tx = pool.begin().await.map_err(|e| {
        ClarifyAsProjectError::Unexpected(anyhow::anyhow!("Failed to begin transaction: {e}"))
    })?;

    let item = inbox_repository::find_inbox_item_by_id(&mut *tx, item_id)
        .await
        .map_err(|e| ClarifyAsProjectError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(ClarifyAsProjectError::NotFound)?;

    if item.user_id() != user_id {
        return Err(ClarifyAsProjectError::Unauthorized);
    }

    let project = Project::new(user_id.clone(), item.title().clone());

    project_repository::insert_project(&mut *tx, &project)
        .await
        .map_err(|e| {
            ClarifyAsProjectError::Unexpected(anyhow::anyhow!("Failed to insert project: {e}"))
        })?;

    let first_action = NextAction::new_for_project(
        user_id.clone(),
        context_id,
        project.id().clone(),
        first_action_title,
    );

    next_action_repository::insert_next_action(&mut *tx, &first_action)
        .await
        .map_err(|e| {
            ClarifyAsProjectError::Unexpected(anyhow::anyhow!(
                "Failed to insert first next action: {e}"
            ))
        })?;

    inbox_repository::delete_inbox_item(&mut *tx, item_id)
        .await
        .map_err(|e| {
            ClarifyAsProjectError::Unexpected(anyhow::anyhow!("Failed to delete inbox item: {e}"))
        })?;

    tx.commit().await.map_err(|e| {
        ClarifyAsProjectError::Unexpected(anyhow::anyhow!("Failed to commit transaction: {e}"))
    })?;

    tracing::info!("Inbox item clarified as project");
    Ok(ClarifyAsProjectResult {
        project,
        first_action,
    })
}

#[derive(Debug, thiserror::Error)]
pub enum ClarifyAsWaitingForError {
    #[error("Inbox item not found")]
    NotFound,
    #[error("Not authorized to clarify this inbox item")]
    Unauthorized,
    #[error("Invalid waiting-on: {0}")]
    InvalidWaitingOn(#[from] WaitingOnError),
    #[error(transparent)]
    Unexpected(anyhow::Error),
}

#[tracing::instrument(
    name = "clarify_as_waiting_for",
    skip(pool, waiting_on),
    fields(item_id = %item_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn clarify_as_waiting_for(
    pool: &PgPool,
    item_id: &InboxItemId,
    user_id: &UserId,
    waiting_on: String,
) -> Result<WaitingForItem, ClarifyAsWaitingForError> {
    let waiting_on = WaitingOn::parse(waiting_on)?;

    let mut tx = pool.begin().await.map_err(|e| {
        ClarifyAsWaitingForError::Unexpected(anyhow::anyhow!("Failed to begin transaction: {e}"))
    })?;

    let item = inbox_repository::find_inbox_item_by_id(&mut *tx, item_id)
        .await
        .map_err(|e| ClarifyAsWaitingForError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(ClarifyAsWaitingForError::NotFound)?;

    if item.user_id() != user_id {
        return Err(ClarifyAsWaitingForError::Unauthorized);
    }

    let wf_item = WaitingForItem::new(user_id.clone(), item.title().clone(), waiting_on);

    waiting_for_repository::insert_waiting_for_item(&mut *tx, &wf_item)
        .await
        .map_err(|e| {
            ClarifyAsWaitingForError::Unexpected(anyhow::anyhow!(
                "Failed to insert waiting-for item: {e}"
            ))
        })?;

    inbox_repository::delete_inbox_item(&mut *tx, item_id)
        .await
        .map_err(|e| {
            ClarifyAsWaitingForError::Unexpected(anyhow::anyhow!(
                "Failed to delete inbox item: {e}"
            ))
        })?;

    tx.commit().await.map_err(|e| {
        ClarifyAsWaitingForError::Unexpected(anyhow::anyhow!("Failed to commit transaction: {e}"))
    })?;

    tracing::info!("Inbox item clarified as waiting for");
    Ok(wf_item)
}

